import"./modulepreload-polyfill-B5Qt9EMX.js";/* empty css               */document.addEventListener("DOMContentLoaded",()=>{console.log("Landing page loaded"),document.querySelectorAll('a[href^="#"]').forEach(o=>{o.addEventListener("click",function(n){n.preventDefault();const e=this.getAttribute("href");if(e==="#")return;const t=document.querySelector(e);t&&t.scrollIntoView({behavior:"smooth"})})})});
